// Headless render harness — screenshots the real getHtml() webview against a
// deterministic fixture snapshot in Chromium. Output is reproducible: same
// fixture → same timestamps → same image bytes.
//
// Usage: node scripts/screenshot.mjs [outDir]
// The fixture is generated by scripts/make-sample-run.mjs before this script runs.
// npm run screenshots wires the two steps together.
//
// Captures (per theme: dark + light):
//   dashboard-<theme>.png          full page
//   dashboard-<theme>-top.png      above-the-fold viewport
//   dashboard-<theme>-agents.png   Agents tab (default)
//   dashboard-<theme>-findings.png Findings tab
//   dashboard-<theme>-timeline.png Timeline tab

import { build } from 'esbuild';
import { chromium } from 'playwright';
import * as os from 'node:os';
import * as path from 'node:path';
import * as fs from 'node:fs';
import { randomBytes } from 'node:crypto';
import { makeSampleRun, FAKE_NOW_SECS } from './make-sample-run.mjs';

// Output dir for screenshots (committed to the repo for the README gallery).
const outDir = process.argv[2] || 'media/screenshots';
// Containment check: refuse to write outside the project root to prevent
// path-traversal via a malicious CLI argument (mirrors the fixtureBase guard below).
const resolvedOut = path.resolve(outDir);
const projectRoot = path.resolve('.');
if (!resolvedOut.startsWith(projectRoot + path.sep) && resolvedOut !== projectRoot) {
  throw new Error(`outDir ${resolvedOut} is outside project root ${projectRoot} — refusing`);
}
fs.mkdirSync(resolvedOut, { recursive: true });

// ---------------------------------------------------------------------------
// Build fixture
// ---------------------------------------------------------------------------

// Write the deterministic fixture into a temp dir so it doesn't pollute the
// repo. The dir is recreated on each run ensuring a clean slate.
const fixtureBase = path.join(os.tmpdir(), 'cwd-screenshot-fixture');
if (fs.existsSync(fixtureBase)) {
  // Safety check: refuse to rmSync a path that isn't actually under os.tmpdir().
  // This guards against TMPDIR/TEMP/TMP environment-variable poisoning in CI which
  // could cause os.tmpdir() to return a project directory and delete real work.
  const tmpRoot = os.tmpdir();
  if (!fixtureBase.startsWith(tmpRoot + path.sep) && fixtureBase !== tmpRoot) {
    throw new Error(`fixtureBase ${fixtureBase} is not under tmpdir ${tmpRoot} — refusing rmSync`);
  }
  fs.rmSync(fixtureBase, { recursive: true, force: true });
}
// Discovery expects the structure: <base>/<proj>/<anything>/workflows/<wf_*>/
// We add two intermediate directories to satisfy findWorkflowDir's parent='workflows' check.
const fixtureWorkflowsBase = path.join(fixtureBase, 'sample-project', 'subagents', 'workflows');
fs.mkdirSync(fixtureWorkflowsBase, { recursive: true });
const wfDir = makeSampleRun(fixtureWorkflowsBase);
console.log('fixture:', wfDir);

// ---------------------------------------------------------------------------
// Bundle host modules (esbuild → ESM in-memory)
// ---------------------------------------------------------------------------

async function loadModule(entry) {
  const r = await build({
    entryPoints: [entry],
    bundle: true,
    format: 'esm',
    write: false,
    platform: 'node',
  });
  return import('data:text/javascript,' + encodeURIComponent(r.outputFiles[0].text));
}

const { getHtml }       = await loadModule('src/webview/html.ts');
const { buildSnapshot } = await loadModule('src/data/snapshot.ts');

// ---------------------------------------------------------------------------
// Build snapshot from fixture (no live FS reads after this point)
// ---------------------------------------------------------------------------

const snap = buildSnapshot({
  base: fixtureBase,
  repo: '',
  refreshMs: 4000,
  statusBar: true,
  roleRules: [],
});

if (!snap.ok) {
  console.error('buildSnapshot failed:', snap.msg);
  process.exit(1);
}

console.log(
  'snapshot ok runId=%s agents=%d findings=%d superseded=%d',
  snap.runId, snap.agents.length, snap.allFindings.length, snap.loop.superseded,
);

// ---------------------------------------------------------------------------
// Theme palettes — realistic VS Code dark/light CSS custom properties
// ---------------------------------------------------------------------------

const DARK = {
  '--vscode-foreground': '#cccccc',
  '--vscode-editor-background': '#1e1e1e',
  '--vscode-font-family': '-apple-system,system-ui,sans-serif',
  '--vscode-editor-font-family': 'monospace',
  '--vscode-sideBar-background': '#252526',
  '--vscode-sideBarSectionHeader-background': '#2d2d2d',
  '--vscode-panel-border': '#3c3c3c',
  '--vscode-editorWidget-background': '#252526',
  '--vscode-badge-background': '#4d4d4d',
  '--vscode-badge-foreground': '#ffffff',
  '--vscode-button-background': '#0e639c',
  '--vscode-button-foreground': '#ffffff',
  '--vscode-button-hoverBackground': '#1177bb',
  '--vscode-focusBorder': '#007fd4',
  '--vscode-charts-blue': '#3794ff',
  '--vscode-charts-green': '#89d185',
  '--vscode-charts-red': '#f48771',
  '--vscode-charts-orange': '#d18616',
  '--vscode-charts-yellow': '#cca700',
  '--vscode-inputValidation-warningBorder': '#c4a000',
  '--vscode-inputValidation-warningForeground': '#cccccc',
  '--vscode-descriptionForeground': '#8b8b8b',
  '--vscode-textLink-foreground': '#3794ff',
  '--vscode-errorForeground': '#f48771',
  '--vscode-list-hoverBackground': '#2a2d2e',
  '--vscode-tab-activeBackground': '#1e1e1e',
  '--vscode-tab-inactiveBackground': '#2d2d2d',
};

const LIGHT = {
  ...DARK,
  '--vscode-foreground': '#333333',
  '--vscode-editor-background': '#ffffff',
  '--vscode-sideBar-background': '#f3f3f3',
  '--vscode-sideBarSectionHeader-background': '#e7e7e7',
  '--vscode-panel-border': '#d4d4d4',
  '--vscode-editorWidget-background': '#f3f3f3',
  '--vscode-badge-background': '#c4c4c4',
  '--vscode-badge-foreground': '#333333',
  '--vscode-button-background': '#007acc',
  '--vscode-button-foreground': '#ffffff',
  '--vscode-charts-blue': '#006ab1',
  '--vscode-charts-green': '#388a34',
  '--vscode-charts-red': '#a1260d',
  '--vscode-charts-orange': '#804c0a',
  '--vscode-charts-yellow': '#795e26',
  '--vscode-descriptionForeground': '#717171',
  '--vscode-textLink-foreground': '#006ab1',
  '--vscode-errorForeground': '#a1260d',
  '--vscode-list-hoverBackground': '#e8e8e8',
  '--vscode-tab-activeBackground': '#ffffff',
  '--vscode-tab-inactiveBackground': '#ececec',
};

// ---------------------------------------------------------------------------
// Chromium — use cached binary when available; fall back to Playwright default
// ---------------------------------------------------------------------------

// Find a cached Chromium across any home dir / build number (avoids hardcoding a
// machine-specific path or pinning a Playwright build that may not be installed).
function findCachedChrome() {
  if (process.env.PW_CHROME && fs.existsSync(process.env.PW_CHROME)) return process.env.PW_CHROME;
  const roots = [path.join(os.homedir(), '.cache/ms-playwright'), '/root/.cache/ms-playwright'];
  for (const root of roots) {
    let dirs;
    try { dirs = fs.readdirSync(root); } catch { continue; }
    for (const d of dirs) {
      if (!d.startsWith('chromium-') || d.includes('headless')) continue;
      for (const sub of ['chrome-linux64/chrome', 'chrome-linux/chrome']) {
        const p = path.join(root, d, sub);
        if (fs.existsSync(p)) return p;
      }
    }
  }
  return undefined;
}
const execPath = findCachedChrome();
const browser = await chromium.launch(execPath ? { executablePath: execPath } : {});

// ---------------------------------------------------------------------------
// Per-tab capture — activate a tab by clicking its button, then screenshot
// ---------------------------------------------------------------------------

/**
 * Activate a tab by its key ('agents', 'findings', 'timeline', …) then
 * scroll back to top and screenshot the viewport.
 */
async function captureTab(page, tabKey, filePath) {
  // Click the tab button. Tab buttons carry data-tabkey="<key>" in the webview.
  const btn = page.locator(`[data-tabkey="${tabKey}"]`).first();
  const count = await btn.count();
  if (count === 0) {
    console.log(`  tab "${tabKey}" button not found — skipping`);
    return;
  }
  await btn.click();
  await page.waitForTimeout(200);
  // Scroll the main content area back to top so the screenshot shows the start.
  await page.evaluate(() => {
    const main = document.getElementById('tab-content') || document.getElementById('root');
    if (main) main.scrollTop = 0;
    window.scrollTo(0, 0);
  });
  await page.waitForTimeout(100);
  await page.screenshot({ path: filePath, fullPage: false });
  console.log('  wrote', filePath);
}

// ---------------------------------------------------------------------------
// Render loop — dark + light
// ---------------------------------------------------------------------------

try {
for (const [theme, vars, bg] of [['dark', DARK, '#1e1e1e'], ['light', LIGHT, '#ffffff']]) {
  // Generate a fresh nonce per theme iteration so each render exercises an independent
  // nonce, matching the extension.ts pattern (randomBytes per activation) and ensuring
  // the harness does not reuse a value that could mask nonce-collision scenarios.
  const nonce = randomBytes(16).toString('base64');
  // Stub acquireVsCodeApi before the webview's inline script runs (CSP-safe).
  // Override Date.now() to produce deterministic 'now' timestamps for timeline bar widths.
  // 'run' agents use now as their end time; without a fixed 'now', their bars extend to
  // real wall-clock time, making timeline screenshots non-deterministic across machines.
  // NOTE: _FAKE_NOW_SECS was removed from the production timelinePanel() code to avoid
  // a test-only global hook in production; Date.now override is the correct alternative.
  const apiStub = `<script nonce="${nonce}">window.acquireVsCodeApi=function(){var _s=null;return{postMessage:function(){},setState:function(s){_s=s;},getState:function(){return _s;}};};Date.now=function(){return ${FAKE_NOW_SECS}*1000;};</script>`;

  console.log('rendering theme:', theme);
  const page = await browser.newPage({ viewport: { width: 1280, height: 900 }, deviceScaleFactor: 2 });
  page.on('pageerror', (e) => console.log('  PAGEERR:', e.message));
  page.on('console', (m) => { if (m.type() === 'error') console.log('  CONSOLE.ERR:', m.text()); });

  // Inject the stub before the webview's inline script so acquireVsCodeApi is available.
  // getHtml() is called with only nonce; the remaining parameters use their defaults
  // (changedMaxMin=15, maxAgents=200, mode='panel', staleSecs=180) because the fixture
  // is purpose-built to match those defaults and the harness does not have a cfg object.
  // If getHtml defaults change, update this call to pass explicit values.
  const html = getHtml(nonce).replace('<body>', '<body>' + apiStub);
  await page.setContent(html, { waitUntil: 'load' });

  // Apply theme variables via JS property assignment (CSP-safe — not innerHTML style=).
  // CSP-bypass: intentional for screenshot harness — page.evaluate runs in the page's JS context
  // and can set inline styles without violating the nonce-restricted CSP. This is not a
  // runtime code path; it is only used during screenshot generation. The actual webview CSP
  // enforcement is covered by the unit tests in test/extension-invariants.test.ts.
  await page.evaluate(({ vars, bg }) => {
    for (const [k, v] of Object.entries(vars)) document.documentElement.style.setProperty(k, v);
    document.body.style.background = bg;
  }, { vars, bg });

  // Strip workflowDir before dispatching to the page — matches the production safeSnap()
  // contract enforced by extension.ts and asserted in extension-invariants.test.ts.
  // Prevents the local tmpdir path from being embedded in page context or CI artifacts.
  const { workflowDir: _wd, ...safeSnapObj } = snap;
  // Dispatch the snapshot message to populate the dashboard.
  await page.evaluate((sn) => {
    window.dispatchEvent(new MessageEvent('message', { data: { type: 'snapshot', snap: sn } }));
  }, safeSnapObj);

  await page.waitForTimeout(600);

  const rootLen = await page.evaluate(() => document.getElementById('root')?.innerHTML.length || 0);
  console.log(`  root innerHTML length: ${rootLen}`);

  // Full-page screenshot
  const fullPath = path.join(resolvedOut, `dashboard-${theme}.png`);
  await page.screenshot({ path: fullPath, fullPage: true });
  console.log('  wrote', fullPath);

  // Above-the-fold screenshot
  const topPath = path.join(resolvedOut, `dashboard-${theme}-top.png`);
  await page.screenshot({ path: topPath, fullPage: false });
  console.log('  wrote', topPath);

  // Per-tab screenshots — Agents, Findings, Timeline
  await captureTab(page, 'agents',   path.join(resolvedOut, `dashboard-${theme}-agents.png`));
  await captureTab(page, 'findings', path.join(resolvedOut, `dashboard-${theme}-findings.png`));
  await captureTab(page, 'timeline', path.join(resolvedOut, `dashboard-${theme}-timeline.png`));

  await page.close();
}
} finally {
  await browser.close();
}
console.log('done. screenshots in:', resolvedOut);
